"""
mkt-original: Leviticus 5-7
Run: python3 scripts/zc-original-leviticus-5-7.py
Covers: the guilt offering (asham) cases (ch5), burnt/grain/sin offering regulations (ch6),
        and guilt/peace offering law with fat-blood prohibitions (ch7).
Key terms: asham, chattat, olah, minchah, shelamim, ma'al, karet, todah, azkarah, tamid.
"""

import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LEVITICUS_ORIGINAL = {
  "5": {
    "1": "<p><strong>nefesh ki techeta</strong> (a soul/person who sins): the subject of Lev 5 is the individual in specific sinful situations. The four cases in vv. 1-4 all begin with <em>nefesh</em> (soul/person) as the moral agent. <strong>veshama qol alah</strong> (heard the voice of an oath/curse): the witness who heard the public adjuration to testify but remained silent. <strong>venasa avono</strong> (he bears his iniquity/guilt): the expression <em>nasa avon</em> (to bear iniquity) is the standard formula for unabsolved moral burden — guilt that remains on the person until resolved. Its opposite is <em>nasa avon</em> in the sense of &lsquo;forgive&rsquo; (God bearing/taking away the iniquity, e.g., Exod 34:7). The guilt of the silent witness: failure to speak up in a legal process is a sin requiring atonement.</p>",
    "2": "<p><strong>asher yiga bechol davar tamei</strong> (who touches any unclean thing): the touchability of impurity is a core Levitical axiom — uncleanness transfers by contact. <strong>venelam mimenu</strong> (and it was hidden from him): inadvertent contact is still real contact; the uncleanness accrues even without awareness. <strong>vehu tamei ve-ashem</strong> (and he is unclean and guilty, verb <em>asham</em>): the verb <em>asham</em> (to be/become guilty, to incur guilt) is distinct from the noun <em>asham</em> (guilt offering). Both appear in this chapter: the verb describes the state; the noun describes the remedy. The Hebrew legal system takes unconscious infraction seriously — objective guilt accumulates even when subjective awareness is absent.</p>",
    "3": "<p><strong>tumat adam</strong> (human uncleanness): the category of impurity arising from contact with human bodily states (discharge, skin disease, corpse). <strong>venelam mimenu</strong> (was hidden from him): the second occurrence of the &lsquo;hidden/unaware&rsquo; qualifier. The repeated emphasis on inadvertent impurity in vv. 2-4 establishes an important theological principle: the gap between what we know and what is actually true about our moral state. The guilt offering (asham) provides a remedy precisely for this gap — sin whose existence one may not even know about.</p>",
    "4": "<p><strong>ki yishava letabei bifei</strong> (who swears rashly with his lips): the adjective <em>bitui</em> (rash utterance) describes an impulsive, unconsidered oath. <strong>lehara o leheitiv</strong> (to do evil or to do good): the oath may have been to do something harmful or something beneficial — what makes it a sin is its rashness and subsequent neglect. <strong>venelam mimenu</strong> (was hidden from him): the same formula for the third time, here in the context of forgotten oaths. The principle: a vow taken and not kept, even if forgotten, creates a real moral obligation that requires resolution. The NT counterpart: James 5:12, &lsquo;let your yes be yes and your no be no.&rsquo;</p>",
    "5": "<p><strong>vehitvadah asher chata aleha</strong> (he shall confess the sin he has committed): the verb <em>hitvadah</em> (Hitpael of <em>yadah</em>) is the technical term for liturgical confession. This is the first step in the atonement process — oral acknowledgment of specific sin precedes the sacrificial offering. The sequence established here (awareness → confession → sacrifice → atonement) is the fundamental structure of OT repentance. In the NT, 1 John 1:9 (&lsquo;if we confess our sins, he is faithful and just to forgive us our sins&rsquo;) preserves the same structure, with Christ&apos;s sacrifice as the permanent ground of atonement.</p>",
    "6": "<p><strong>vehevi et ashamo laYHWH</strong> (he shall bring his guilt offering to YHWH): the Hebrew noun <em>asham</em> appears here as the technical offering-type for these cases. There is a complexity in Lev 5 that has puzzled translators: vv. 1-13 use both <em>chattat</em> (sin offering) and <em>asham</em> (guilt offering) apparently interchangeably (v.6 calls it both <em>asham</em> and <em>chattat</em>). The scholarly consensus is that in this section the two terms overlap; the stricter distinction (asham for violations of property rights or sacred objects, chattat for impurity and inadvertent sin) is clearer in chs 4-5:13. <strong>nikapper alav hakohen mechatatoh</strong> (the priest makes atonement for his sin): the verb <em>kipper</em> (Piel) is the atonement-making act. The full range of <em>kipper</em> covers: &lsquo;to cover,&rsquo; &lsquo;to wipe clean,&rsquo; &lsquo;to ransom.&rsquo; All three nuances apply to what Christ&apos;s sacrifice accomplishes.</p>",
    "7": "<p><strong>ve&apos;im lo tashig yado dei seh</strong> (if his hand cannot reach [the value of] a sheep): the idiomatic <em>lo tashig yado</em> (his hand does not reach) is the Levitical expression for financial inability. The graduated sacrifice system in vv. 7-13 is theologically significant: YHWH adjusts the atonement mechanism to the offerer&apos;s means. A poor person&apos;s turtledoves are as effective as a wealthy person&apos;s lamb; a destitute person&apos;s flour is as effective as the doves. Atonement is not a privilege of the wealthy. The same principle governs the NT: Christ&apos;s sacrifice is equally available to all, regardless of economic status (Gal 3:28; Rev 22:17).</p>",
    "8": "<p><strong>veqarav el hakohen</strong> (he shall bring it to the priest): the priest as mediator is essential — the offerer cannot self-administer atonement. <strong>vemalaq et rosho mikol erpo</strong> (he wrings its head from its neck without completely severing it): the specific slaughter method for birds differs from four-footed animals (which are slit at the throat). The wringing separates without severing — a detail prescribed and specific. The precision of the sacrificial instructions communicates that YHWH&apos;s atonement mechanism is exactly specified, not approximated.</p>",
    "9": "<p><strong>vehizah middam hachatat al qir hamizbeach</strong> (he sprinkles some of the blood of the sin offering on the side of the altar): blood manipulation is the critical act in all sacrifice. The blood goes to the altar — the divine &lsquo;address&rsquo; — not merely discarded. <strong>vehanish&apos;ar badam yimatzei el yesod hamizbeach chattat hu</strong> (the remainder of the blood is drained at the base — it is a sin offering): blood at the base of the altar is the prescribed disposal. The blood declares the offering&apos;s nature: the animal&apos;s life poured out in the place of the offerer&apos;s life.</p>",
    "10": "<p><strong>veet hasheni ya'aseh olah kamishpat</strong> (the second bird he offers as a burnt offering according to the prescribed procedure): the two-bird offering for the poor: one chattat (sin offering) for the atonement function, one olah (burnt offering) for the dedication/consecration function. The pairing reflects the dual dimension of restored covenant relationship: sin dealt with (chattat) + self re-presented to YHWH (olah). <strong>venislach lo</strong> (and he is forgiven): the declarative formula of forgiveness — the sacrificial outcome is stated as completed, not hoped-for. The same finality characterizes NT forgiveness through Christ (Heb 10:14).</p>",
    "11": "<p><strong>ve&apos;im lo tasig yado lishnei torim</strong> (if his hand cannot afford even two turtledoves): the second concession. <strong>asirit ha-ephah solet</strong> (a tenth of an ephah of fine flour): approximately 2.3 liters of flour — the minimum possible offering. <strong>lo yasim aleiha shemen</strong> (he must not put oil on it): the flour offering for the poor is stripped of oil (the characteristic of the grain offering, minchah) to signal that it is not a minchah but functions as a chattat. <strong>ve-lo yiten aleiha levonah</strong> (nor shall he add frankincense): similarly stripped of incense. The deliberate differentiation signals that the medium is fully interchangeable with blood for the purpose of atonement when poverty demands it — while maintaining the theological distinctions of the system.</p>",
    "12": "<p><strong>veqamatz hakohen mimenu melo qumtzo</strong> (the priest takes from it a handful, his fistful): the <em>kometz</em> (handful, the amount a fist can grasp) is the priest&apos;s act that transforms the grain into a sacrifice. <strong>azkaratah</strong> (its memorial portion, <em>azkarah</em>): the portion burned on the altar — the noun derives from <em>zakar</em> (to remember/mention). The <em>azkarah</em> is the portion that &lsquo;mentions&rsquo; the offerer before YHWH — the God-ward dimension of the sacrifice. The concept of memorial/remembrance before God is central to the Passover (Exod 12:14: <em>zikkaron</em>, memorial), and the Lord&apos;s Supper is explicitly a memorial (&lsquo;do this in remembrance of me,&rsquo; 1 Cor 11:24-25).</p>",
    "13": "<p><strong>vekipper alav hakohen al chatato</strong> (the priest makes atonement for him for his sin): identical outcome formula as v.6 — the flour-atonement is fully effective. <strong>vehayeta lakohen kaminchah</strong> (it shall belong to the priest, as with the grain offering): the remainder of the flour sacrifice goes to the priests — the economy of the temple system sustains the priestly ministry from the substance of the people&apos;s atonement offerings. The principle recurs throughout Lev 6-7 in the detailed priestly portions.</p>",
    "14": "<p>A new divine speech formula: <strong>vayedaber YHWH el Moshe lemor</strong> (YHWH spoke to Moses, saying) — marking the transition to a distinct section. Lev 5:14-19 introduces the <em>asham</em> proper: the guilt/reparation offering for trespass against holy things (<em>me&apos;ilah</em>, sacred encroachment). The previous section (vv. 1-13) used &lsquo;asham&rsquo; loosely for various sin offerings; here the technical distinction begins: the asham is specifically for violations that require reparation in addition to atonement.</p>",
    "15": "<p><strong>nefesh ki tim&apos;ol ma&apos;al</strong> (a soul who commits a trespass/act of unfaithfulness): the verb <em>ma&apos;al</em> (to trespass, commit sacrilege, act treacherously) carries a connotation of covenant violation beyond mere error. It appears in contexts of violation of sacred trust: Numbers 5:6 (unfaithfulness against YHWH), Joshua 7:1 (Achan&apos;s <em>ma&apos;al</em>), Ezek 18:24 (apostasy). <strong>bequdshei YHWH</strong> (against YHWH&apos;s holy things): misappropriation of consecrated property — using for secular purposes what belongs to YHWH. <strong>ve-asham</strong> (he becomes guilty): the state before offering. <strong>ayil tamim</strong> (a flawless ram): the asham requires a ram — a more substantial animal than the lamb/goat of the chattat, reflecting the reparative dimension of this offering.</p>",
    "16": "<p><strong>ve-et asher chata min haqodesh yeshalem</strong> (he shall make restitution for what he sinned against the holy thing): the asham is unique among offerings in requiring both the sacrificial act AND financial restitution. <strong>vachamishito yosif alav</strong> (and shall add a fifth to it): a 20% surcharge on the value of the misappropriated sacred property. The combination of sacrifice + restitution + penalty communicates: atonement is not merely an internal religious act but includes concrete redress for objective harm. The NT counterpart: Zacchaeus&apos;s fourfold restitution (Luke 19:8) illustrates the same principle — genuine repentance makes restitution where possible.</p>",
    "17": "<p><strong>ve&apos;im nefesh ki techeta ve-ashetah achat mikol mitzvot YHWH asher lo te&apos;asenah veloh yada</strong> (if a soul sins by doing any one of the things YHWH has commanded not to be done, though he did not know it): this is the most expansive case — sin against any divine commandment, even without awareness. <strong>ve-asham venasa avono</strong> (and he becomes guilty and bears his iniquity): the guilt is objective and real regardless of subjective knowledge. This verse establishes the principle of objective guilt: the moral order has an objective reality that conscience may not track. Romans 5:12-14 expresses the NT version: sin reigned even before the law was given explicitly, because the objective moral order existed before its codification.</p>",
    "18": "<p><strong>vehevi ayil tamim min hatzon</strong> (he shall bring a flawless ram from the flock): the asham for unknown violation of a commandment requires the same ram as for known misappropriation of sacred things (v.15). The equal atonement for known and unknown sin reflects a consistent theology: the remedy is determined by the nature of the offence (violation of the divine order), not by the quality of the offender&apos;s awareness. <strong>al shiggatoh asher lo yada</strong> (for the unintentional error he did not know): <em>shegagah</em> (error, inadvertence) is the technical term for unintentional sin throughout the sacrificial system — it contrasts with <em>be-yad ramah</em> (with a high/defiant hand, Num 15:30), for which no sacrifice is prescribed.</p>",
    "19": "<p><strong>asham hu asham asham laYHWH</strong> (it is a guilt offering — he has truly incurred guilt before YHWH): the emphatic declaration closes the asham section of ch5. The repetition (<em>asham asham</em>) is emphatic: this is genuinely an asham-case, a real guilt incurred before YHWH. The emphatic language addresses a potential objection: how can one be truly guilty for something one did not know? Answer: guilt before YHWH is defined by objective violation of the divine order, not by subjective awareness. The remedy is therefore also objective: the asham ram&apos;s blood provides real, not merely symbolic, atonement for real, not merely felt, guilt.</p>"
  },
  "6": {
    "1": "<p>A new divine speech formula marking the beginning of a distinct subsection. Lev 6:1-7 (English; Hebrew 5:20-26) closes the asham laws by addressing interpersonal fraud and theft — and classifying these as covenant offences against YHWH himself. The section demonstrates that the horizontal and vertical dimensions of sin are inseparable: cheating a neighbor is simultaneously trespassing against YHWH.</p>",
    "2": "<p><strong>nefesh ki techeta uma&apos;ala ma&apos;al baYHWH</strong> (a soul who sins and commits a trespass against YHWH): the key interpretive move of this section: interpersonal fraud — lying about a deposit, robbery, deception of a neighbor — is categorized as <em>ma&apos;al baYHWH</em> (trespass against YHWH). The horizontal wrong (against the neighbor) is simultaneously a vertical wrong (against YHWH). <strong>piqqadon</strong> (deposit, entrustment): a common commercial arrangement in the ancient Near East, governed by its own legal codes (Hammurabi §§120-126). The Levitical law classifies the violation of such trust as sacred encroachment, not merely civil wrong.</p>",
    "3": "<p><strong>o nefesh asher yishava al shaqer</strong> (or a person who swears falsely): the false oath is the climactic case — it invokes YHWH&apos;s name in support of a lie, compounding the interpersonal fraud with blasphemy. The categories in vv. 2-3 (deposit fraud, robbery, extortion, lost-property fraud, false oath) are unified by their common structure: using speech or relationship to take what belongs to another. This is the sin of deception in economic relationships — a violation of the ninth commandment (&lsquo;do not bear false witness&rsquo;) applied to commercial life.</p>",
    "4": "<p><strong>vehayah ki yecheta ve-ashem</strong> (when he has sinned and is guilty): the causal <em>vehayah ki</em> (&lsquo;and it shall be when&rsquo;) marks the consequence. <strong>veheshiv et hagazel asher gazal</strong> (he shall return what he took by robbery): the verb <em>shub</em> (Hiphil: <em>heshiv</em>) = &lsquo;restore, return, make restitution.&rsquo; The atonement process for interpersonal fraud requires <em>first</em> returning the stolen goods — confession and sacrifice without restitution is incomplete. This is the OT foundation for the NT principle that reconciliation with the offended party precedes valid worship: &lsquo;if you are offering your gift at the altar and there remember that your brother has something against you, first go and be reconciled&rsquo; (Matt 5:23-24).</p>",
    "5": "<p><strong>al kol asher yishava alav lashaqer veshallem oto verosho yosif alav chamishitav</strong> (for anything about which he swore falsely — he shall make full restitution, adding one-fifth of it): the 20% surcharge (<em>chamishit</em>) is the same penalty as for misappropriation of sacred property (5:16). The theological implication: a neighbor&apos;s property, protected by oath, has the same sacred status as temple property. <strong>beyom ashmatoh</strong> (on the day of his guilt offering): the restitution precedes or accompanies the sacrifice — not a deferrable obligation but an immediate one.</p>",
    "6": "<p><strong>ve-et ashamo yavi laYHWH ayil tamim</strong> (he shall bring his guilt offering to YHWH — a flawless ram): after restitution comes sacrifice. The order is significant: economic justice first, then ritual atonement. The asham ram for interpersonal fraud is identical to the asham for violating sacred things (5:15) — confirming that the neighbor&apos;s property is as sacred as temple property in YHWH&apos;s sight.</p>",
    "7": "<p><strong>venikhpar lav lifnei YHWH</strong> (atonement is made for him before YHWH): the atonement formula closing the asham section. <strong>vekhol asher ya&apos;aseh le&apos;echad mekulam asher yit&apos;ashma bah</strong> (for anything he may have done to incur guilt): the comprehensive scope — the asham covers the full range of covenant violations enumerated in vv. 2-5. The forgiveness formula confirms: the combination of restitution + sacrifice provides complete resolution of both the horizontal wrong (the neighbor is made whole) and the vertical wrong (YHWH&apos;s covenant is repaired).</p>",
    "8": "<p>Another divine speech formula: <strong>vayedaber YHWH el Moshe lemor</strong>. The section vv. 8-13 begins the &lsquo;priestly torah&rsquo; or &lsquo;instructions for the offerings&rsquo; — a different literary genre from the preceding &lsquo;case law&rsquo; format of chs 4-6:7. Lev 6:8-7:38 provides the officiants&apos; manual for handling each sacrifice, including the priestly portions. The divine speech marking a new section also signals a change in addressee: previously addressed to the people (via Moses), now addressed to Aaron and the priests.</p>",
    "9": "<p><strong>zot torat ha-olah</strong> (this is the Torah of the burnt offering): the <em>torat</em> formula introduces each major section of the priestly manual (cf. 6:14, 25; 7:1, 11). <strong>hi ha-olah al moqtah al hamizbeach kol halailah</strong> (the burnt offering remains on its hearth on the altar all night): the olah is unique among offerings in being entirely consumed on the altar — no portion for priests or offerer. Its all-night burning distinguishes it: the fire continues even when the worshiping community is absent, asserting the continuous character of Israel&apos;s consecration to YHWH. <strong>veha&apos;eish hamizbeach tuqad bo</strong> (the fire of the altar shall be kept burning on it): the perpetual fire is the subject of the next unit.</p>",
    "10": "<p><strong>velabash hakohen middo bad</strong> (the priest puts on his linen garment): the linen (<em>bad</em>) priestly garments — white, undyed, non-wool — are the standard dress for the daily service. <strong>venas et hadeshan el mitz ad lamizbeach</strong> (he takes up the ashes left from the burnt offering on the altar and places them beside the altar): the removal of ashes is a ritual act requiring the priestly vestments. Even the disposal of what remains after the sacrifice is governed by holiness protocols — nothing about YHWH&apos;s altar is treated as ordinary refuse.</p>",
    "11": "<p><strong>ufashat et begadav velabash begadim acherim</strong> (he shall take off his garments and put on other clothes): a change of garments for the ash-removal journey. The holy vestments are worn in the sanctuary; ordinary clothes are worn for the ash disposal outside the camp. The same principle of contextual holiness — different sacred protocols for different spaces — governs the movement between the altar (holy) and the ash-dump (clean but not holy).</p>",
    "12": "<p><strong>veha&apos;eish al hamizbeach tuqad bo</strong> (the fire on the altar must be kept burning): repeated from v.9 to frame vv. 10-11 as an interruption. <strong>uveer alav hakohen etzim baboqer baboqer</strong> (the priest shall add wood to it every morning): the daily wood-feeding is the priest&apos;s first morning act. The fire that began at the altar&apos;s inauguration (Lev 9:24: fire from before YHWH) must never be allowed to go out — it is the sign of YHWH&apos;s ongoing acceptance and presence.</p>",
    "13": "<p><strong>eish tamid tuqad al hamizbeach lo tichbeh</strong> (a continual fire shall be kept burning on the altar; it shall not go out): the <em>tamid</em> principle (continual, perpetual) is fundamental to Levitical worship. Multiple elements of the tabernacle/temple service are <em>tamid</em>: the fire (6:13), the lampstand (Exod 27:20), the bread of the Presence (Exod 25:30), the incense (Exod 30:8). The <em>tamid</em> offerings frame Israel&apos;s life in perpetual liturgy. Revelation 4:8 (&lsquo;day and night they never cease to say, Holy, holy, holy&rsquo;) is the new covenant&apos;s eternal <em>tamid</em> — continuous worship before YHWH.</p>",
    "14": "<p><strong>vezot torat haminchah</strong> (this is the Torah of the grain offering): the minchah section begins. <strong>bene Aharon yaqrivu otah lifnei YHWH el penei hamizbeach</strong> (Aaron&apos;s sons shall offer it before YHWH, in front of the altar): the grain offering instructions are now addressed to the officiants. The grain offering (<em>minchah</em>, gift/tribute) consists of fine flour, oil, and salt; it accompanies other offerings and is sometimes made as a standalone gift. It represents the offerer&apos;s produce — the agricultural domain consecrated to YHWH.</p>",
    "15": "<p><strong>veheram mimenu bequmtzo misolet haminchah umishamnah</strong> (a priest takes a handful from the grain offering — from the flour and oil): the <em>kometz</em> procedure for the minchah: a fistful is taken and burned as the <em>azkarah</em> (memorial portion). <strong>al kol halevonah asher al haminchah</strong> (and all the frankincense that is on the grain offering): all the frankincense is burned even though only a handful of flour. The <em>azkarah</em> rises before YHWH as <em>reyach nichoach</em> (pleasing aroma) — the ascending smoke is the &lsquo;memorial&rsquo; portion that keeps the offerer in YHWH&apos;s remembrance.</p>",
    "16": "<p><strong>vehannoteret mimenu yochaluhu Aharon uvanav</strong> (what remains Aaron and his sons eat): the remainder of the grain offering is priestly food. <strong>matzot te&apos;achel</strong> (it shall be eaten without leaven/yeast): unleavened bread is required in the holy precinct. The absence of leaven in the priestly food connects to Passover theology — leaven represents the old, corrupted life; unleavened bread is the food of the redeemed, the holy, the new (cf. Paul in 1 Cor 5:7-8: &lsquo;let us celebrate the festival... with the unleavened bread of sincerity and truth&rsquo;).</p>",
    "17": "<p><strong>lo te&apos;afeh chametz</strong> (it shall not be baked with leaven): repeated and emphatic. <strong>chelqam natati otah me&apos;ishai</strong> (I have given it as their portion from my food offerings): the priestly portion is explicitly YHWH&apos;s gift to the priests — &lsquo;my food offerings&rsquo; means the offerings belong to YHWH first; he then grants the priests their portion. The same principle governs the NT ministry: those who serve the altar share in the altar&apos;s provisions (1 Cor 9:13-14). <strong>kodesh kodashim hi kachatat uchaasham</strong> (it is most holy, like the sin offering and the guilt offering): the grain offering&apos;s remainder is classified as <em>kodesh kodashim</em> (most holy) — the highest sanctity grade, which restricts consumption to the sanctuary precincts and to male priests only.</p>",
    "18": "<p><strong>kol zachar bibne Aharon yochalenu</strong> (every male among Aaron&apos;s sons may eat it): the gender restriction on <em>kodesh kodashim</em> consumption reflects the priestly grading system: holiest things require maximum qualification (full-status male priests only). <strong>chuqat olam ledoroteichem</strong> (a permanent statute throughout your generations): the <em>chuqat olam</em> formula marks permanent, unchangeable ordinances. <strong>kol asher yiga bahem yiqdash</strong> (whoever touches them becomes holy): &lsquo;contagious holiness&rsquo; — contact with the most holy things conveys holiness. This principle is the inverse of the impurity-transfer principle: as uncleanness transfers by contact, so does holiness. Christ&apos;s &lsquo;contagious holiness&rsquo; is the NT expression: touching him heals and cleanses (Mark 1:41; Luke 8:46).</p>",
    "19": "<p>Another divine speech formula: the ordination offering section (vv. 19-23) follows. This is the daily grain offering of the high priest — not a one-time event but the permanent daily practice instituted at ordination.</p>",
    "20": "<p><strong>zeh qorban Aharon uvanov</strong> (this is the offering of Aaron and his sons): the high priest&apos;s personal offering is distinct from his mediatorial offerings for the people. <strong>asirit ha-ephah solet minchah tamid</strong> (a tenth of an ephah of fine flour as a regular grain offering): the same amount as the poorest person&apos;s offering (5:11) — the high priest offers what the destitute person offers! This theological leveling communicates that the high priest himself depends on the mercy of atonement; he is not above the system he administers. <strong>chatzi baboqer vechatzi ba&apos;arev</strong> (half in the morning and half in the evening): the twice-daily framing of the priestly day. The <em>tamid</em> sacrifice (Num 28:3-8) structures Israel&apos;s daily worship at morning and evening.</p>",
    "21": "<p><strong>al machabat bashemen te&apos;aseh</strong> (it shall be prepared on a griddle with oil): the ordination offering is a cooked grain offering. <strong>murbeket tavienah</strong> (bring it well mixed/soaked): the preparation method ensures a specific texture. The detail of the high priest&apos;s daily offering is provided with precision — nothing in the priestly service is improvised or left to preference. The exactness of YHWH&apos;s instructions models the exactness of Christ&apos;s obedience: not approximately what the Father required, but precisely (Phil 2:8: &lsquo;obedient to death, even death on a cross&rsquo;).</p>",
    "22": "<p><strong>vehakohen hamashiach tachtav mibanov ya&apos;aseh otah</strong> (the anointed priest who succeeds him among his sons shall offer it): the ordination offering is inherited — the successor priest continues the same daily offering pattern. The continuity of the anointed priest&apos;s daily offering models the continuity of Israel&apos;s priestly ministry. <strong>khalil le-YHWH tuktar</strong> (it shall be entirely burned to YHWH): the high priest&apos;s grain offering is entirely consumed — no portion is eaten. The same logic as the burnt offering: the officiant who intercedes for others offers himself entirely, retaining nothing for himself.</p>",
    "23": "<p><strong>vekol minchah lakohen kalil tihyeh lo te&apos;achel</strong> (every grain offering from a priest shall be entirely burned; it shall not be eaten): the general rule confirmed: priests&apos; own grain offerings are entirely YHWH&apos;s. When priests eat the people&apos;s grain offerings (v.16), that is the appointed portion from YHWH; but priests cannot eat their own offerings, which belong entirely to God. The self-offering of the priest is total and unreserved.</p>",
    "24": "<p>A fourth divine speech formula in this chapter, introducing the sin offering instructions for priests (vv. 24-30). The shift to direct address to Aaron and the priests continues.</p>",
    "25": "<p><strong>zot torat hachatat</strong> (this is the Torah of the sin offering): the priestly manual for the chattat. <strong>bimqom asher yishachet ha-olah tishachet hachatat</strong> (in the place where the burnt offering is slaughtered, the sin offering shall be slaughtered): the slaughter location of the chattat is the same as the olah — the north side of the altar (Lev 1:11). The spatial alignment communicates the equivalence of the two: both are equally legitimate, equally holy, at the same place before YHWH. <strong>qodesh qodashim hi</strong> (it is most holy): the sin offering meat is classified as <em>kodesh kodashim</em> — the highest holiness grade.</p>",
    "26": "<p><strong>hakohen hamechaper otah yochalenah</strong> (the priest who offers it as a sin offering shall eat it): the priest who performs the atonement rite eats the sin offering&apos;s meat. This is the economic provision for the Levitical priesthood but also has theological significance: the priest who handles the sin offering participates in it. <strong>bimaqom qadosh te&apos;achel bechatzar ohel mo&apos;ed</strong> (in a holy place it shall be eaten, in the court of the tent of meeting): the location restriction confines the sin-offering meal to the sanctuary precinct. The sanctity of the meat requires a holy context for consumption.</p>",
    "27": "<p><strong>kol asher yiga bivisarah yiqdash</strong> (whoever touches its flesh becomes holy): &lsquo;contagious holiness&rsquo; extended to the sin offering&apos;s flesh. The sin offering — which carries the sin of the offerer through the priest&apos;s act — is itself <em>kodesh kodashim</em> and communicates holiness to whatever touches it. The paradox: the vessel of sin-bearing becomes the most holy object. Christ as the sin-bearer (&lsquo;him who knew no sin to be sin for us,&rsquo; 2 Cor 5:21) is the ultimate &lsquo;most holy&rsquo; thing — and contact with him through faith sanctifies (Heb 2:11: &lsquo;the one who sanctifies and those who are sanctified are all of one family&rsquo;).</p>",
    "28": "<p><strong>ukhli cheres asher tevushal bo yishaber</strong> (the clay pot in which it was cooked must be broken): clay is porous and absorbs the fluids of whatever is cooked in it. A clay pot that has absorbed sin-offering residue must be destroyed — the absorbed holiness cannot be fully removed from the absorbent material. <strong>keli nechoshet</strong> (a bronze pot): bronze, being non-porous and scourable, can be cleaned. The distinction between porous (clay) and non-porous (bronze) materials in relation to absorbed sanctity illustrates the concrete, physical theology of the Levitical system — holiness has real material implications.</p>",
    "29": "<p><strong>kol zachar bakohanim yochal otah qodesh qodashim hi</strong> (every male among the priests may eat it; it is most holy): the sin offering&apos;s meat is restricted to male priests in the sanctuary. The graduated access of the sacrificial system mirrors the graduated approach to YHWH: the holy of holies (high priest only once per year), the holy place (priests only), the court (all Israel), outside the court (Gentiles, excluded). The NT dissolution of these gradations is the theological argument of Hebrews and Ephesians: in Christ, the full access of the most holy is opened to all (Heb 10:19-22; Eph 2:18).</p>",
    "30": "<p><strong>vekol chatat asher yuva midamah el ohel mo&apos;ed lekapper bakodesh lo te&apos;achel ba&apos;eish tisaref</strong> (no sin offering whose blood is brought into the tent of meeting to make atonement in the holy place shall be eaten; it shall be burned with fire): the key rule distinguishing ordinary sin offerings from the special ones. When the sin offering&apos;s blood is taken inside the veil (as in Yom Kippur, Lev 16, and the offerings for priest and congregation, Lev 4:3-21), the entire carcass must be burned outside the camp — it cannot be eaten. The reason: the blood has entered the most holy place carrying the sin burden; the associated flesh is too charged for ordinary consumption. Hebrews 13:11-12 applies this: Jesus suffered &lsquo;outside the gate&rsquo; as the fulfillment of the burned sin-offering whose blood entered the most holy place.</p>"
  },
  "7": {
    "1": "<p><strong>vezot torat ha-asham qodesh qodashim hu</strong> (this is the Torah of the guilt offering; it is most holy): the fifth <em>torat</em> formula. The asham is assigned the highest holiness grade (<em>qodesh qodashim</em>). The prominence of this designation reflects the asham&apos;s function: it deals with violations that require reparation — the most serious category of inadvertent sin against YHWH&apos;s property (holy things) and against neighbor (6:1-7). Its blood goes to the altar as the most holy things; its meat is eaten only by male priests in the sanctuary.</p>",
    "2": "<p><strong>bimqom asher yishachatu et ha-olah yishachatu et ha-asham</strong> (in the place where the burnt offering is slaughtered, the guilt offering shall be slaughtered): the same location rule as the sin offering (6:25) — the north side of the altar. <strong>ve-et damo yizroq al hamizbeach saviv</strong> (its blood shall be thrown/sprinkled against all sides of the altar): the blood manipulation for the asham uses <em>zaraq</em> (throw/dash), the same verb as for the burnt offering (1:5) and peace offering (3:2). The blood covers all four sides of the altar — comprehensive atonement in every direction.</p>",
    "3": "<p><strong>veet kol chelbo yaqriv mimenu</strong> (he shall offer all the fat from it): the fat portions are YHWH&apos;s portion in all animal sacrifices. The asham&apos;s fat offering follows the same pattern as the peace offering (ch3): the fat tail, the fat covering the entrails, both kidneys with their fat, and the lobe of the liver are all burned on the altar. Fat (<em>chelev</em>) in Israelite thought is the richest, most nourishing part of the animal — YHWH&apos;s portion is always the best (see also the firstfruits principle).</p>",
    "4": "<p><strong>ushte hakliayot vehachelev asher aleihen</strong> (the two kidneys with the fat on them): the kidneys in Hebrew anthropology are the seat of deep inner life and conscience (cf. Ps 7:9; 16:7; Jer 11:20 — YHWH searches the kidneys). The offering of the kidneys to YHWH symbolizes the consecration of one&apos;s deepest interior life, one&apos;s most hidden self. <strong>veyoteret al hakaved al hakliayot yesirenah</strong> (the lobe of the liver, which he shall remove with the kidneys): the liver and kidneys are the internal organs most associated with life and divination in the ancient Near East (cf. Ezek 21:21 for pagan liver divination). Their dedication to YHWH asserts that the seat of life and knowledge belongs to him alone.</p>",
    "5": "<p><strong>vehiqtir otam hakohen hamizbeach ishah laYHWH</strong> (the priest burns them on the altar as a food offering to YHWH): <em>qetoret</em> (burning offering, smoke) — the fat burns into smoke and rises as the divine portion. <em>Ishah laYHWH</em> (&lsquo;food offering to YHWH,&rsquo; sometimes translated &lsquo;fire offering&rsquo; but better as &lsquo;food gift&rsquo;) is the technical term for the altar&apos;s upward portion. The entire sacrificial system uses the metaphor of God receiving a meal — not because YHWH needs food (Ps 50:12-13: &lsquo;I will not accept a bull from your house or goats from your folds&rsquo;) but because the metaphor communicates covenant fellowship: the host and guest share a meal.</p>",
    "6": "<p><strong>kol zachar bakohanim yochalenah</strong> (every male among the priests may eat it): as with the sin offering, the asham meat is restricted to male priests. <strong>bimaqom qadosh ye&apos;achel qodesh qodashim hu</strong> (it shall be eaten in a holy place; it is most holy): the sanctuary context requirement for <em>qodesh qodashim</em> consumption. The two-fold holiness restriction (gender and location) enforces the graduated holiness system: the closer one is to the divine center, the stricter the requirements.</p>",
    "7": "<p><strong>kahatat ka-asham torat achat lahem</strong> (like the sin offering, like the guilt offering — one law governs them both): the summary equation of the two most important purification offerings. Despite the distinctions in application (chattat for impurity and inadvertent sin; asham for violated trust and property violations), they share the same procedural law: priestly consumption, most holy status, same-location slaughter. <strong>hakohen asher yechapper bo lo yihyeh</strong> (the priest who makes atonement with it shall have it): the officiating priest receives the sin and guilt offering meats. This is the economic provision for the priesthood from the atonement offerings — the ministry of reconciliation sustains those who perform it.</p>",
    "8": "<p><strong>vehakohen hamaqriv et olat ish or ha-olah asher hiqriv lakohen lo tihyeh</strong> (the priest who offers a man&apos;s burnt offering shall keep the hide of the burnt offering he offered): the burnt offering is entirely consumed on the altar — but its hide remains. The priest who offers the burnt offering receives the hide. Leather was commercially significant in the ancient world; this provision supplements the priestly income from a portion not itself consecrated to the altar. The detailed listing of priestly portions in 7:8-36 reflects the comprehensive economic system supporting the Levitical ministry.</p>",
    "9": "<p><strong>vekhol minchah asher te&apos;afeh batanur</strong> (every grain offering baked in an oven): three types of grain offering preparation: oven-baked, pan-prepared, and griddle-prepared. All baked grain offerings go to the officiating priest. The variety of preparation methods reflects the practical realities of the ancient kitchen — YHWH&apos;s instructions are embedded in real economic and culinary life, not abstracted from it.</p>",
    "10": "<p><strong>vekhol minchah belulah vashemen vachaevah lekol bene Aharon tihyeh ish keachiv</strong> (every grain offering mixed with oil or dry shall be shared equally among all Aaron&apos;s sons): the distribution rule for non-baked grain offerings. Unlike the baked offering (which goes to the officiant), mixed grain offerings are shared equally among all the priests. <em>Ish keachiv</em> (each like his brother) — equal distribution regardless of rank. The priestly fraternity is characterized by material equality even while it has functional hierarchy (high priest over priests over Levites).</p>",
    "11": "<p><strong>vezot torat zevach hashelamim</strong> (this is the Torah of the sacrifice of the fellowship offerings): the peace offering section. <em>Shelamim</em> (fellowship/peace offerings, from <em>shalom</em>) is the most communal of the offerings: its meat is shared between YHWH (the fat), the priests (portions), and the offerer and family (the rest). It is the covenant meal — YHWH and the offerer eating together. The three subcategories of shelamim are introduced: thanksgiving (<em>todah</em>, v.12), vow offering (<em>neder</em>, v.16), and freewill offering (<em>nedavah</em>, v.16).</p>",
    "12": "<p><strong>im al todah yaqrivenhu</strong> (if he offers it as a thanksgiving): the <em>todah</em> (thanksgiving offering) is the most urgent shelamim — it must be eaten on the same day (v.15). <strong>vehiqriv al zevach hatodah challot matzot</strong> (he shall offer with it unleavened cakes): the todah includes a complex bread offering: unleavened loaves mixed with oil, unleavened wafers spread with oil, and fine-flour cakes well mixed with oil — three types of unleavened bread. The abundance of accompanying bread signals the festive, celebratory character of the thanksgiving offering.</p>",
    "13": "<p><strong>al challot lechem chametz yaqriv qorbano</strong> (along with unleavened cakes, he shall bring leavened bread as his offering with his thanksgiving fellowship offering): the todah uniquely includes leavened bread alongside the unleavened. The presence of leavened bread in the thanksgiving context (though it is never burned on the altar — only the unleavened portions are offered to YHWH) reflects the ordinary bread of daily life joining the sacred feast. The thanksgiving includes the ordinary alongside the consecrated.</p>",
    "14": "<p><strong>vehiqriv mimenu echad mikol qorban terumah laYHWH</strong> (he shall present one from each offering as a contribution to YHWH): the wave bread (<em>terumah</em>, contribution/heave offering) — one loaf from each type presented as YHWH&apos;s portion before being given to the priest. <strong>lakohen hazoreq et dam hashelamim lo yihyeh</strong> (it belongs to the priest who throws the blood of the fellowship offerings): the priest who performs the blood manipulation receives the wave bread — the officiating minister&apos;s portion connects his act to its liturgical reward.</p>",
    "15": "<p><strong>uvevar zevach todat shelamav beyom qorbano ye&apos;achel</strong> (the meat of the thanksgiving fellowship offering shall be eaten on the day it is offered): the todah must be consumed entirely on the offering day. <strong>lo yaniach mimenu ad boqer</strong> (none of it may be left until morning): no leftovers from the thanksgiving. The urgency of complete consumption on the offering day reflects the character of thanksgiving: gratitude is immediate, whole, and urgent. What remains unexpressed until &lsquo;another day&rsquo; is not gratitude but its deferral. Paul echoes this urgency: &lsquo;giving thanks always and for everything&rsquo; (Eph 5:20).</p>",
    "16": "<p><strong>ve&apos;im neder o nedavah zevach qorbano</strong> (if his sacrifice is a vow offering or a freewill offering): two-day consumption for vow and freewill offerings — more relaxed than the todah. The distinction communicates: the vow and freewill offerings express ongoing commitment and spontaneous generosity rather than immediate response to specific divine grace. The different time-frames are fitting: thanksgiving is urgent; ongoing dedication is sustained.</p>",
    "17": "<p><strong>vehannotar mivevar hazevach bayom hashelishi ba-eish yisaref</strong> (any remaining meat from the sacrifice on the third day must be burned up with fire): the absolute limit on three-day-old meat from peace offerings. The burning prevents the sacred meat from becoming ordinary food. <strong>bayom hashelishi</strong> (on the third day): the three-day deadline is curious — the same three-day pattern appears in other significant contexts (Hos 6:2: &lsquo;on the third day he will raise us up&rsquo;; 1 Cor 15:4: &lsquo;raised on the third day according to the Scriptures&rsquo;). The sacrificial meat that must not remain past the third day is the type of the body that did not remain in the tomb past the third day.</p>",
    "18": "<p><strong>ve&apos;im he&apos;achol ye&apos;achel mibesar zevach shelamav bayom hashelishi lo yeratze</strong> (if any of the fellowship offering is eaten on the third day, it will not be accepted): <em>lo yeratze</em> (it will not be accepted, not found acceptable) — the technical term for YHWH&apos;s rejection of an offering. <strong>piggul yihyeh</strong> (it is tainted, <em>piggul</em>): <em>piggul</em> (offensive, detestable) — a sacrifice that has gone bad beyond the ordained time. <strong>venashea avono</strong> (the one who eats it bears his iniquity): tainted-offering consumption is itself a sin requiring atonement. The boundary of legitimate sacrifice is not negotiable by the offerer&apos;s convenience.</p>",
    "19": "<p><strong>vehavesar asher yiga bekol tamei lo ye&apos;achel</strong> (meat that touches any unclean thing shall not be eaten): the contagious impurity principle applied to sacrificial meat. As holiness communicates by contact (6:18, 27), so impurity communicates by contact. Sacrificial meat that has become contaminated must be destroyed. <strong>ve-habasar kol tahor yochal et habasar</strong> (the clean meat — all who are ritually clean may eat it): the positive rule: clean meat may be eaten by all ritually clean persons, not just priests. The peace offering is the democratic sacrifice — shared broadly.</p>",
    "20": "<p><strong>vehanefesh asher tochel basar mizevach hashelamim asher laYHWH vetum&apos;ato alav</strong> (if a person eats the flesh of the fellowship offering belonging to YHWH while his uncleanness is on him): the grave offense: eating sacred meat in a state of impurity. <strong>venichretah hanefesh hahiv me&apos;ameha</strong> (that person shall be cut off from his people): the <em>karet</em> penalty — the most severe sanction in the Levitical system. <em>Karet</em> (&lsquo;cutting off&rsquo;) is debated: it may mean premature death, exclusion from the covenant community, or eschatological judgment. All three dimensions are present: violation of the holiness boundary separates from the community of YHWH&apos;s people.</p>",
    "21": "<p><strong>venefesh ki tiga bekol tamei</strong> (if anyone touches anything unclean): the rule extended to any unclean contact before eating peace offering meat. The multiple categories of uncleanness listed (&lsquo;human uncleanness, an unclean animal, or any unclean detestable thing&rsquo;) cover the full range of contamination sources. <strong>venichretah hanefesh hahiv me&apos;ameha</strong>: the <em>karet</em> formula repeated — the holiness of the peace offering fellowship meal is not a matter of preference but of covenant membership.</p>",
    "22": "<p>A new divine speech formula introducing the fat and blood prohibitions (vv. 22-27), the fundamental dietary restrictions related to sacrifice. These are addressed to &lsquo;the people of Israel&rsquo; — not merely the priests but the whole covenant community.</p>",
    "23": "<p><strong>kol chelev shor vechesef ve-ez lo tocheilu</strong> (you shall eat no fat — whether from ox, sheep, or goat): the <em>chelev</em> (suet/hard fat, the internal sacrificial fat) prohibition. This fat is YHWH&apos;s portion in all animal sacrifice. It is distinguished from <em>shuman</em> (ordinary fat/suet) which may be eaten. The specific fat forbidden is the <em>chelev</em> of sacrificeable animals (ox, sheep, goat) — not fat in general. YHWH claims the richest portion; the prohibition enforces that claim on the whole community, not just during the offering but in all domestic consumption of these animals.</p>",
    "24": "<p><strong>vechelev neveilah vechelev terefa ye&apos;aseh lekol melacha</strong> (the fat of an animal that dies of itself or is torn by wild animals may be put to other use): the fat of naturally dead (<em>neveilah</em>) or torn (<em>terefah</em>) animals — which cannot be offered — may be used for other purposes (leather-working, lamp fuel, etc.) but not for food. The distinction: YHWH&apos;s portion from living animals must not be eaten; the same fat from non-offering animals is not for human food (being still YHWH&apos;s in principle) but may be used for other purposes.</p>",
    "25": "<p><strong>ki kol ochel chelev min habehemah asher yaqriv mimena ishah laYHWH</strong> (anyone who eats the fat of an animal from which a food offering may be made to YHWH): the <em>karet</em> penalty for eating the forbidden fat. The same cutting-off threatened for eating the peace offering in impurity (v.20) applies here — eating YHWH&apos;s portion is as grave as eating sacred meat while unclean. The consistency of the <em>karet</em> penalty across multiple violations communicates that the holiness boundary is equally serious wherever it appears.</p>",
    "26": "<p><strong>vekhol dam lo tocheilu bechol moshivoteichem</strong> (you shall eat no blood of any kind in any of your dwelling places): the blood prohibition is universal — not limited to sacrificial contexts but extending to &lsquo;all your dwellings.&rsquo; Blood is prohibited both because it is the bearer of life (Lev 17:11) and because it belongs to YHWH as the atonement mechanism. The prohibition applies to birds and land animals — the prohibition extends to the entire animal kingdom available for food.</p>",
    "27": "<p><strong>kol nefesh asher tochel kol dam venichretah hanefesh hahiv me&apos;ameha</strong> (whoever eats any blood shall be cut off from his people): the <em>karet</em> for blood consumption is stated as an absolute principle in a single sentence. The severity of the penalty reflects the theological weight of the blood prohibition: blood = life = YHWH&apos;s atoning mechanism. The one who consumes blood usurps what belongs to YHWH alone and destroys the very mechanism by which atonement is made. The NT explicitly addresses this: the Jerusalem Council retained the blood prohibition for Gentile Christians (Acts 15:20, 29) while the eucharistic &lsquo;drinking the blood of Christ&rsquo; (John 6:53-56) operates in a completely different register — Christ&apos;s blood is not literally consumed but received by faith.</p>",
    "28": "<p>Another divine speech formula introducing the wave and heave portions of the peace offering (vv. 28-34). These specific priestly portions are the subject of a separate divine command — their importance justifies distinct legislative treatment.</p>",
    "29": "<p><strong>medaber el bene Yisrael lemor hamaqriv zevach shelamav laYHWH yavi et qorbano laYHWH mizivcho shelamav</strong> (tell the people of Israel: whoever offers his fellowship sacrifice to YHWH must bring to YHWH his own offering from his fellowship sacrifice): the offerer personally brings the wave offering — this is not delegated to the priest. The personal act of bringing the offering before YHWH is the offerer&apos;s worshipful gesture, not just a delivery mechanism.</p>",
    "30": "<p><strong>yadav teviy&apos;enah et ishei YHWH</strong> (his own hands shall bring the LORD&apos;s food offerings): the offerer&apos;s own hands present the fat and breast before YHWH. <strong>et hachelev al hachazeh yavienah lehaniph oto tenufah lifnei YHWH</strong> (the fat together with the breast — so that the breast may be presented as a wave offering before YHWH): the <em>tenufah</em> (wave offering) involves a back-and-forth movement before the altar — the offerer presents the portion &lsquo;before YHWH,&rsquo; symbolically giving it, then the priest receives it back on YHWH&apos;s behalf. The wave motion enacts the giving-and-receiving of the covenant relationship: the offerer gives; YHWH accepts and provides for the priests.</p>",
    "31": "<p><strong>vehiqtir hakohen et hachelev hamizbeach</strong> (the priest burns the fat on the altar): the fat portion goes up in smoke — YHWH&apos;s portion returns to him as fire and smoke. <strong>vehayah hachazeh leAharon ulvanav</strong> (but the breast shall belong to Aaron and his sons): the breast — the wave offering — becomes the priestly community&apos;s portion. The wave breast feeds all the priests, including the high priest&apos;s household, distributed as a common meal.</p>",
    "32": "<p><strong>ve-et shoq hayamin titenu terumah lakohen</strong> (you shall give the right thigh to the priest as a contribution): the right thigh (<em>shoq hayamin</em>) is the second priestly portion from the peace offering — the &lsquo;heave offering&rsquo; (<em>terumah</em>, contribution, literally &lsquo;lifted up&rsquo;). The right side is consistently the privileged side in Israelite culture (cf. the right hand of God as the place of honor, Ps 110:1). The officiating priest receives the right thigh as his personal portion, distinct from the communal wave breast.</p>",
    "33": "<p><strong>hamaqriv et dam hashelamim vehahelev mibene Aharon lo tihyeh shoq hayamin lemanat</strong> (the son of Aaron who offers the blood and fat of the fellowship offering shall have the right thigh as his portion): the officiating priest specifically — the one who performs the blood and fat manipulation — receives the right thigh. The connection between the ritual act and its economic provision establishes the principle: ministry and provision are linked. Those who do the work of atonement are sustained by the atonement system.</p>",
    "34": "<p><strong>ki et chazeh hatenufa ve-et shoq haterumah laqachti me-et bene Yisrael mizivchei shelameihem</strong> (for I have taken the wave breast and the heave thigh from the Israelites&apos; fellowship offerings): YHWH speaks in first person — &lsquo;I have taken&rsquo; — then &lsquo;I have given them to Aaron the priest and his sons as a perpetual due from the Israelites.&rsquo; The priestly portions are explicitly YHWH&apos;s gift: he first accepts them from the people, then redistributes them to the priests. The economy of provision is triangular: people offer to YHWH, YHWH gives to priests through the people&apos;s offerings. Paul applies the same logic: &lsquo;those who preach the gospel should receive their living from the gospel&rsquo; (1 Cor 9:14), citing explicitly the temple precedent.</p>",
    "35": "<p><strong>zot mishchat Aharon umishchat banav me&apos;ishei YHWH</strong> (this is the portion allotted to Aaron and his sons from YHWH&apos;s food offerings): <em>mishchah</em> (&lsquo;anointing portion&rsquo; or &lsquo;portion&rsquo;) — the same root as <em>mashiach</em> (anointed one). The portion of Aaron (<em>mishchat Aharon</em>) is a term that connects priestly provision to priestly anointing: they receive their portion <em>because</em> they are anointed for the service of YHWH. Christ as the Anointed One (<em>Mashiach</em>, <em>Christos</em>) receives &lsquo;the name above every name&rsquo; (Phil 2:9) as the priestly-royal share for his completed work of atonement.</p>",
    "36": "<p><strong>asher tzivah YHWH latet lahem beyom moshcho otam</strong> (which YHWH commanded to be given them on the day of their anointing): the priestly portions date from the ordination ceremony — they are not a later supplement but an original covenant provision. <strong>chuqat olam ledoroteichem</strong> (a permanent statute throughout their generations): the <em>chuqat olam</em> formula applies to the priestly portions as to all the permanent cultic ordinances. The Levitical priesthood&apos;s economic provision is as permanent as the priesthood itself.</p>",
    "37": "<p><strong>zot hatorah la-olah laminchah velachatat vela-asham velamiullim velizevach hashelamim</strong> (this is the law of the burnt offering, the grain offering, the sin offering, the guilt offering, the ordination offering, and the fellowship offering): a summary formula covering all six major sacrifice types. The six offerings together constitute the complete sacrificial system of the Torah: olah (burnt, vv. 6:8-13), minchah (grain, 6:14-23), chattat (sin, 6:24-30), asham (guilt, 7:1-7), miluim (ordination, Lev 8-9), shelamim (peace/fellowship, 7:11-36). Hebrews reads this entire list as fulfilled in Christ&apos;s one sacrifice: he is the olah (full consecration to God), minchah (pleasing gift), chattat (sin-bearing), asham (reparation), miluim (ordained high priest), and shelamim (peace with God secured).</p>",
    "38": "<p><strong>asher tzivah YHWH et Moshe behar Sinai</strong> (which YHWH commanded Moses on Mount Sinai): the concluding authority citation — the Sinai origin of the sacrificial laws grounds their divine authority. <strong>beyom tzivoto et bene Yisrael lehaqriv et qorbane&apos;hem laYHWH bemidbar Sinai</strong> (on the day he directed the Israelites to bring their offerings to YHWH in the wilderness of Sinai): the wilderness setting is theologically significant — the sacrificial system was given during the period of covenant formation, in the liminal space between Egypt and Canaan. The wilderness is the space of total dependence on YHWH where the covenant protocols were established in their purity, before territorial and political complications.</p>"
  }
}

def main():
    existing = load_comm('mkt-original', 'leviticus')
    merge_comm(existing, LEVITICUS_ORIGINAL)
    save_comm('mkt-original', 'leviticus', existing)
    for ch in ['5', '6', '7']:
        vv = existing.get(ch, {})
        print(f'  ch{ch}: {len(vv)} verse(s) with original commentary')

if __name__ == '__main__':
    main()
